import { ViteSSG } from 'vite-ssg'
import { createHead as createHeadOld } from '@vueuse/head'
import App from './App.vue'
import { routes } from './router'
import './index.css'
import './styles/global.css'

export const createApp = ViteSSG(
  App,
  { routes },
  ({ app, router, isClient, initialState }) => {
    const head = createHeadOld()
    app.use(head)

    if (isClient) {
      // Wait for the app to be fully hydrated
      app.mixin({
        mounted() {
          // Ensure the component is fully mounted
          this.$nextTick(() => {
            // Force a re-render after hydration
            this.$forceUpdate()
          })
        }
      })

      // Add a global error handler
      app.config.errorHandler = (err, vm, info) => {
        console.error('Vue Error:', err, info)
      }
    }

    router.beforeEach((to, from, next) => {
      head.push({
        title: to.meta?.title,
        meta: [
          {
            name: 'description',
            content: to.meta?.description
          },
          {
            property: 'og:title',
            content: to.meta?.title
          },
          {
            property: 'og:description',
            content: to.meta?.description
          }
        ]
      })
      next()
    })
  }
)